import{c as a,S as t,j as s,m as i}from"./chunks/framework.DRSkXQvj.js";const c=JSON.parse('{"title":"Estimating the current size of the 2026 DRC Bundibugyo virus outbreak: a joint Bayesian re-analysis of the McCabe et al. report","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),r={name:"index.md"};function o(n,e,l,h,d,p){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="Estimating-the-current-size-of-the-2026-DRC-Bundibugyo-virus-outbreak:-a-joint-Bayesian-re-analysis-of-the-McCabe-et-al.-report" tabindex="-1">Estimating the current size of the 2026 DRC Bundibugyo virus outbreak: a joint Bayesian re-analysis of the McCabe et al. report <a class="header-anchor" href="#Estimating-the-current-size-of-the-2026-DRC-Bundibugyo-virus-outbreak:-a-joint-Bayesian-re-analysis-of-the-McCabe-et-al.-report" aria-label="Permalink to &quot;Estimating the current size of the 2026 DRC Bundibugyo virus outbreak: a joint Bayesian re-analysis of the McCabe et al. report {#Estimating-the-current-size-of-the-2026-DRC-Bundibugyo-virus-outbreak:-a-joint-Bayesian-re-analysis-of-the-McCabe-et-al.-report}&quot;">​</a></h1><p><strong>Authors:</strong> Sam Abbott, Samuel Brand and Sebastian Funk.</p><p><strong>Last updated:</strong> 20 May 2026. This is a live report, re-run as new data arrive, so the estimates change between updates.</p><p><a href="https://epiforecasts.io/BVDOutbreakSize/stable" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/docs-stable-blue.svg" alt="Stable"></a> <a href="https://epiforecasts.io/BVDOutbreakSize/dev" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/docs-dev-blue.svg" alt="Dev"></a></p><p><strong>Data as of:</strong> 18 May 2026, the release date of the WHO AFRO External Situation Report 01 the counts are taken from. Estimates are reported as of this date; it can lag the update date above.</p><p><a href="https://doi.org/10.5281/zenodo.20312758" target="_blank" rel="noreferrer"><img src="https://zenodo.org/badge/1243778099.svg" alt="DOI"></a></p><p><strong>See:</strong> <a href="/BVDOutbreakSize/dev/analysis#Summary">current outbreak size</a> · <a href="/BVDOutbreakSize/dev/analysis#Comparison-with-McCabe-et-al.">comparison with McCabe et al.</a> · <a href="/BVDOutbreakSize/dev/analysis#How-the-data-streams-compare">how the data streams compare</a> · <a href="/BVDOutbreakSize/dev/analysis#Limitations">limitations</a>.</p><p><strong>Abstract.</strong> An outbreak of Ebola disease caused by Bundibugyo virus (BVD) is ongoing in the Democratic Republic of the Congo (DRC), with cases also detected across the border in Uganda. Estimating the likely current size of the outbreak is useful for the response, but most cases are not yet reported and have to be inferred from the data streams that are available. The Imperial College London report (McCabe et al., <a href="https://www.imperial.ac.uk/mrc-global-infectious-disease-analysis/research-themes/preparedness-and-response-to-emerging-threats/report-ebola-18-05-2026/" target="_blank" rel="noreferrer">18 May 2026</a>, revised in a <a href="https://www.imperial.ac.uk/media/imperial-college/medicine/mrc-gida/Report-ebola-update-20-05-2026.pdf" target="_blank" rel="noreferrer">20 May 2026 update</a>) estimates the size with two analyses, geographic spread from the cases exported to Uganda and back-calculation from suspected deaths in DRC. Building on that work, we re-analyse the same problem as a single joint Bayesian model over the latent cumulative case count, fitting all streams together with priors on the nuisance parameters that the report varies in scenario sweeps. Beyond the exported cases and DRC deaths the report uses, we condition on two further streams, the reported cases in DRC (with an ascertainment component) and the deaths among exported cases in Uganda. We also add a no-onward-transmission projected-deaths counterfactual, a one-week-ahead forecast and an onset-to-death delay sensitivity analysis, and replace two closed-form approximations (the deaths convolution and the small-growth-rate exports term) with their exact forms. We report the joint posterior over the cumulative case count from current data; to separate the effect of newer data from the change in method we also fit the model to the data as of each report version in sequence (18 May, then the 20 May update), comparing against both a joint reimplementation of the report&#39;s approach and its original published estimates at each version.</p><p><strong>Scope.</strong> This work is motivated by adding an external view of the current situation, based on our understanding of real-time infectious disease dynamics and the infection process that gives rise to observed epidemic surveillance counts. We are actively developing it and encourage feedback, so please get in touch. We fully support reuse and adaptation. Find out more in the <a href="https://epiforecasts.io/BVDOutbreakSize/dev/contributing" target="_blank" rel="noreferrer">contributing guide</a>.</p><p><strong>Use of AI:</strong> The model code and analysis were drafted by a language model and reviewed and revised under human oversight; the named authors are responsible for that oversight.</p><p><strong>Why our numbers differ from the Imperial report.</strong> Two reasons. First, the method: we fit all data streams jointly in a single Bayesian model rather than combining separate scenario analyses (the abstract above and the analysis page list the full set of changes). Second, the data: we use the 18 May 2026 snapshot (sources per <a href="https://github.com/epiforecasts/BVDOutbreakSize/blob/main/data/observations.toml" target="_blank" rel="noreferrer"><code>data/observations.toml</code></a>), at or beyond the cut-offs used in either McCabe et al. report version. To separate these two effects we also refit the model to each report version&#39;s own data (18 May, then the 20 May update). The joint posterior assumes a single common cut-off for every data stream, so the counts must be kept in sync to the same date.</p><p>The analysis page sets out <a href="/BVDOutbreakSize/dev/analysis#What-we-do-differently-from-McCabe-et-al.">each way our method departs from the report</a> alongside the matching Imperial method, and reports the <a href="/BVDOutbreakSize/dev/analysis#Results">full joint results</a>.</p><h2 id="Installing-the-package" tabindex="-1">Installing the package <a class="header-anchor" href="#Installing-the-package" aria-label="Permalink to &quot;Installing the package {#Installing-the-package}&quot;">​</a></h2><p>To use the model and the bundled outbreak data from your own Julia environment, add the package from the repository:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Pkg</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Pkg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(url </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://github.com/epiforecasts/BVDOutbreakSize&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>You can then load the model machinery and the data the report is fitted to:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> BVDOutbreakSize</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">obs </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> load_observations</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>This gives you the exported model components, constants and data loaders, enough to build your own analysis on top of the package. Reproducing the full report (fitting the models and writing the result tables and plots) can be done in a few ways, described next.</p><h2 id="Running" tabindex="-1">Running <a class="header-anchor" href="#Running" aria-label="Permalink to &quot;Running {#Running}&quot;">​</a></h2><p>There are a couple of ways to re-fit the model.</p><h3 id="Re-fit-from-a-clone" tabindex="-1">Re-fit from a clone <a class="header-anchor" href="#Re-fit-from-a-clone" aria-label="Permalink to &quot;Re-fit from a clone {#Re-fit-from-a-clone}&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --recurse-submodules</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/epiforecasts/BVDOutbreakSize</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> BVDOutbreakSize</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.instantiate()&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/run.jl</span></span></code></pre></div><p><code>scripts/run.jl</code> fits the models and writes the output CSVs (the analysis literate is also run as part of the docs build). Running <code>docs/examples/analysis.jl</code> directly instead steps through the full narrative.</p><h3 id="Re-fit-without-cloning" tabindex="-1">Re-fit without cloning <a class="header-anchor" href="#Re-fit-without-cloning" aria-label="Permalink to &quot;Re-fit without cloning {#Re-fit-without-cloning}&quot;">​</a></h3><p><code>scripts/reproduce.jl</code> fetches the package, instantiates its environment, and runs the fit:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/epiforecasts/BVDOutbreakSize/main/scripts/reproduce.jl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> julia</span></span></code></pre></div><p>Outputs land in <code>./bvd-output</code>; set <code>BVD_OUTPUT_DIR</code> to write them elsewhere, or <code>BVD_REF</code> to a release tag to reproduce a specific version. The script clones into a temporary directory and runs from there, so it leaves your own Julia environments untouched.</p><h3 id="Render-the-docs-page" tabindex="-1">Render the docs page <a class="header-anchor" href="#Render-the-docs-page" aria-label="Permalink to &quot;Render the docs page {#Render-the-docs-page}&quot;">​</a></h3><p>Executes the literate and produces HTML at <code>docs/build/</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=docs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.develop(PackageSpec(path=pwd())); Pkg.instantiate()&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=docs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs/make.jl</span></span></code></pre></div><p>Updating the observation counts for a new sitrep is a single-file edit of <code>data/observations.toml</code>; the literate picks the new numbers up automatically.</p><h2 id="Outputs-and-releases" tabindex="-1">Outputs and releases <a class="header-anchor" href="#Outputs-and-releases" aria-label="Permalink to &quot;Outputs and releases {#Outputs-and-releases}&quot;">​</a></h2><p>Each push to <code>main</code> regenerates the model outputs as part of the documentation build and publishes them as a GitHub Release. The <a href="https://github.com/epiforecasts/BVDOutbreakSize/releases/latest" target="_blank" rel="noreferrer">latest release</a> bundles the saved result tables and plots, thinned posterior draws, a copy of the input <code>observations.toml</code> that produced them, a <code>site.zip</code> snapshot of the rendered report site, and <code>analysis.html</code>, a self-contained single-file copy of the report that opens offline (<a href="https://github.com/epiforecasts/BVDOutbreakSize/releases/latest/download/analysis.html" target="_blank" rel="noreferrer">download the latest</a>); the same artifacts are written to the repository&#39;s <code>output/</code> directory on each build. Browse <a href="https://github.com/epiforecasts/BVDOutbreakSize/releases" target="_blank" rel="noreferrer">all releases</a> for earlier output bundles — major versions of the report are kept as GitHub Releases.</p><p>The rendered report is published from the <a href="https://github.com/epiforecasts/BVDOutbreakSize/tree/gh-pages" target="_blank" rel="noreferrer"><code>gh-pages</code> branch</a>, where past and development versions of the analysis page can be found.</p><h2 id="Submodules" tabindex="-1">Submodules <a class="header-anchor" href="#Submodules" aria-label="Permalink to &quot;Submodules {#Submodules}&quot;">​</a></h2><ul><li><code>external/bdbv-linelist-analysis</code> — Bayesian reanalysis of the 2012 Isiro BDBV line list (Rosello et al. 2015). Source of the informative onset-to-death gamma shape and scale priors.</li></ul><h2 id="Citation" tabindex="-1">Citation <a class="header-anchor" href="#Citation" aria-label="Permalink to &quot;Citation {#Citation}&quot;">​</a></h2><p>If you use or build on this project, please cite the three works this repository depends on:</p><ul><li><p><strong>This project</strong> — Abbott, S., Brand, S., Funk, S. (2026). <em>BVDOutbreakSize: joint forward-generative Turing model for the 2026 DRC Bundibugyo outbreak.</em> <a href="https://github.com/epiforecasts/BVDOutbreakSize" target="_blank" rel="noreferrer">https://github.com/epiforecasts/BVDOutbreakSize</a>. DOI: <a href="https://doi.org/10.5281/zenodo.20312758" target="_blank" rel="noreferrer">10.5281/zenodo.20312758</a>.</p></li><li><p><strong>Imperial reports</strong> that this work re-implements and compares against, in both released versions — McCabe, R., Ebbarnezh, L., Okware, S., Fotsing, R., Koua, E., Mbaka, P., Lofungola, A., van Elsland, S. L., McMenamin, M., Ferguson, N., le Polain de Waroux, O., Cori, A. (2026). <em>Estimation of the size of the outbreak of Ebola disease caused by Bundibugyo virus in DRC.</em> Imperial College London, 18 May 2026. DOI: <a href="https://doi.org/10.25560/130007" target="_blank" rel="noreferrer">10.25560/130007</a>. <a href="https://www.imperial.ac.uk/mrc-global-infectious-disease-analysis/research-themes/preparedness-and-response-to-emerging-threats/report-ebola-18-05-2026/" target="_blank" rel="noreferrer">Report page</a>. McCabe, R. and others (2026). <em>Estimation of the size of the Ebola outbreak caused by Bundibugyo virus in DRC: May 20, 2026 update.</em> Imperial College London, 20 May 2026. DOI: <a href="https://doi.org/10.25560/13005307" target="_blank" rel="noreferrer">10.25560/13005307</a>. <a href="https://www.imperial.ac.uk/media/imperial-college/medicine/mrc-gida/Report-ebola-update-20-05-2026.pdf" target="_blank" rel="noreferrer">Report PDF</a>.</p></li><li><p><strong>Onset-to-death delay reanalysis</strong> that this work uses for delay priors — Funk, S. (2026). <em>bdbv-linelist-analysis: Bayesian reanalysis of the 2012 Isiro Bundibugyo line list.</em> <a href="https://github.com/sbfnk/bdbv-linelist-analysis" target="_blank" rel="noreferrer">https://github.com/sbfnk/bdbv-linelist-analysis</a>.</p></li></ul><h2 id="Further-references" tabindex="-1">Further references <a class="header-anchor" href="#Further-references" aria-label="Permalink to &quot;Further references {#Further-references}&quot;">​</a></h2><ul><li><p>Rosello et al., <em>Ebola virus disease in DRC, 1976–2014</em>, eLife 2015. Original Isiro 2012 onset-to-death gamma point estimate.</p></li><li><p>Imai et al., <em>Estimating the potential total number of novel coronavirus cases in Wuhan City</em>, Imperial COVID-19 Response Team Report 1, 17 January 2020. Methodological template for Method 1.</p></li><li><p>Charniga et al., <em>Best practices for estimating and reporting epidemiological delay distributions</em>, PLOS Computational Biology 2024. Followed for the delay-distribution reporting here.</p></li></ul>`,41)])])}const g=a(r,[["render",o]]);export{c as __pageData,g as default};
